const body = $json.body || $json;
const payload = body.payload || body;
const tenant = payload.tenant || {};
const invoice = payload.invoice || {};
const rule = payload.rule || {};
function digits(v){ return String(v || '').replace(/\D/g, ''); }
const phone = digits(tenant.phone || payload.phone || '');
const paymentUrl = invoice.payment_url || payload.payment_url || '';
const message = payload.message || `Olá, ${tenant.name || 'cliente'}. Existe uma cobrança em aberto no RS Connect. ${paymentUrl ? 'Link: ' + paymentUrl : ''}`;
return [{ json: {
  event: body.event || payload.event || rule.event || 'billing.reminder',
  tenant_id: body.tenant_id || payload.tenant_id || tenant.id,
  flow_id: body.flow_id || payload.flow_id || null,
  callback_url: body.callback?.url || payload.callback?.url || body.callback_url || payload.callback_url || '',
  callback_token: body.callback?.token || payload.callback?.token || body.callback_token || payload.callback_token || '',
  company_name: tenant.name || '', email: tenant.email || '', phone,
  invoice_number: invoice.number || '', amount: invoice.amount || 0, due_date: invoice.due_date || '', payment_url: paymentUrl, message
} }];
